/// C: static void funcargs(LexState *ls, expdesc *f)
fn funcargs(ls: &mut LexState, state: &mut LuaState, f: &mut ExprDesc) -> Result<(), LuaError> {
    let mut args = ExprDesc::default();
    let line = ls.linenumber;
